import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useLanguage } from '../../contexts/LanguageContext';
import { loanService } from '../../services/loanService';
import { 
  CurrencyDollarIcon,
  CalendarIcon,
  CalculatorIcon,
  CheckCircleIcon,
  ExclamationTriangleIcon,
  ArrowPathIcon,
  ClockIcon
} from '@heroicons/react/24/outline';

interface Currency {
  id: string;
  symbol: string;
  name: string;
  full_name: string;
  description: string;
  is_featured: boolean;
}

interface LoanCalculation {
  currency: {
    id: string;
    name: string;
    symbol: string;
  };
  loan_amount_currency: string;
  loan_amount_usd: string;
  exchange_rate: string;
  duration_months: number;
  fee_percentage: string;
  fee_amount_usd: string;
  total_amount_usd: string;
  monthly_payment_usd: string;
  interest_rate: string;
}

const LoanApplication: React.FC = () => {
  const navigate = useNavigate();
  const { state: authState } = useAuth();
  const { t } = useLanguage();

  const [currencies, setCurrencies] = useState<Currency[]>([]);
  const [calculation, setCalculation] = useState<LoanCalculation | null>(null);
  const [loading, setLoading] = useState(false);
  const [calculating, setCalculating] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  const [formData, setFormData] = useState({
    currency_id: '',
    loan_amount: '',
    duration_months: 12,
    fee_percentage: 2.5,
  });

  useEffect(() => {
    // Allow access if KYC is approved OR under review
    if (authState.user?.kyc_status === 'pending' || authState.user?.kyc_status === 'rejected') {
      navigate('/kyc');
      return;
    }
    loadCurrencies();
  }, [authState.user, navigate]);

  const loadCurrencies = async () => {
    try {
      const response = await loanService.getAvailableCurrencies();
      setCurrencies(response);

      // Auto-select USD if available
      const usd = response.find((c: any) => c.symbol === 'USD');
      if (usd) {
        setFormData(prev => ({ ...prev, currency_id: usd.id }));
      }
    } catch (err) {
      setError('Failed to load currencies');
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'duration_months' ? parseInt(value) : 
               name === 'fee_percentage' ? parseFloat(value) : value,
    }));

    // Clear calculation when inputs change
    if (calculation) {
      setCalculation(null);
    }
    if (error) setError('');
  };

  const calculateLoan = async () => {
    if (!formData.currency_id || !formData.loan_amount) {
      setError('Please select currency and enter loan amount');
      return;
    }

    setCalculating(true);
    setError('');

    try {
      const response = await loanService.calculateLoan({
        currency_id: formData.currency_id,
        loan_amount: formData.loan_amount,
        duration_months: formData.duration_months,
        fee_percentage: formData.fee_percentage,
      });
      setCalculation(response);
    } catch (err: any) {
      setError(err.response?.data?.error || 'Calculation failed');
    } finally {
      setCalculating(false);
    }
  };

  const submitApplication = async () => {
    if (!calculation) {
      setError('Please calculate loan terms first');
      return;
    }

    setSubmitting(true);
    setError('');

    try {
      const response = await loanService.createApplication({
        currency: formData.currency_id,
        loan_amount_currency: formData.loan_amount,
        duration_months: formData.duration_months,
        fee_percentage: formData.fee_percentage,
      });

      if (response.approved) {
        navigate('/loans/payment', { 
          state: { 
            application: response.application,
            message: response.message 
          }
        });
      } else {
        setError(response.message || 'Application was not approved');
      }
    } catch (err: any) {
      setError(err.response?.data?.error || 'Application failed');
    } finally {
      setSubmitting(false);
    }
  };

  const selectedCurrency = currencies.find(c => c.id === formData.currency_id);

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 py-12">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
            {t('applyLoan')}
          </h1>
          <p className="mt-2 text-gray-600 dark:text-gray-400">
            Get interest-free cryptocurrency financing with competitive fees
          </p>
        </div>

        {/* KYC Status Info */}
        {authState.user?.kyc_status === 'under_review' && (
          <div className="mb-8 rounded-md bg-blue-50 dark:bg-blue-900/20 p-4 border border-blue-200 dark:border-blue-700">
            <div className="flex">
              <ClockIcon className="h-5 w-5 text-blue-400" />
              <div className="ml-3">
                <h3 className="text-sm font-medium text-blue-800 dark:text-blue-200">
                  KYC Under Review
                </h3>
                <p className="mt-2 text-sm text-blue-700 dark:text-blue-300">
                  Your KYC is being reviewed. You can apply for loans during this process.
                </p>
              </div>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Application Form */}
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-8">
            <h2 className="text-xl font-semibold text-gray-900 dark:text-white mb-6">
              Loan Details
            </h2>

            {error && (
              <div className="mb-6 rounded-md bg-red-50 dark:bg-red-900/20 p-4">
                <div className="text-sm text-red-700 dark:text-red-400">{error}</div>
              </div>
            )}

            <div className="space-y-6">
              {/* Currency Selection */}
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Currency *
                </label>
                <select
                  name="currency_id"
                  value={formData.currency_id}
                  onChange={handleInputChange}
                  className="block w-full px-3 py-3 border border-gray-300 dark:border-gray-600 rounded-lg shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent dark:bg-gray-700 dark:text-white"
                >
                  <option value="">Select a currency</option>
                  {currencies.map((currency) => (
                    <option key={currency.id} value={currency.id}>
                      {currency.symbol} - {currency.name}
                      {currency.is_featured && ' ⭐'}
                    </option>
                  ))}
                </select>
                {selectedCurrency && (
                  <p className="mt-2 text-sm text-gray-500 dark:text-gray-400">
                    {selectedCurrency.description}
                  </p>
                )}
              </div>

              {/* Loan Amount */}
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Loan Amount ({selectedCurrency?.symbol || 'Currency'}) *
                </label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <CurrencyDollarIcon className="h-5 w-5 text-gray-400" />
                  </div>
                  <input
                    type="number"
                    name="loan_amount"
                    value={formData.loan_amount}
                    onChange={handleInputChange}
                    step="0.00000001"
                    min="0"
                    className="block w-full pl-10 pr-3 py-3 border border-gray-300 dark:border-gray-600 rounded-lg shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent dark:bg-gray-700 dark:text-white"
                    placeholder="Enter amount"
                  />
                </div>
              </div>

              {/* Duration */}
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Loan Duration *
                </label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <CalendarIcon className="h-5 w-5 text-gray-400" />
                  </div>
                  <select
                    name="duration_months"
                    value={formData.duration_months}
                    onChange={handleInputChange}
                    className="block w-full pl-10 pr-3 py-3 border border-gray-300 dark:border-gray-600 rounded-lg shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent dark:bg-gray-700 dark:text-white"
                  >
                    <option value={6}>6 months</option>
                    <option value={12}>12 months</option>
                    <option value={18}>18 months</option>
                    <option value={24}>24 months</option>
                    <option value={36}>36 months</option>
                    <option value={48}>48 months</option>
                    <option value={60}>60 months</option>
                  </select>
                </div>
              </div>

              {/* Fee Percentage */}
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Processing Fee (%)
                </label>
                <div className="relative">
                  <input
                    type="number"
                    name="fee_percentage"
                    value={formData.fee_percentage}
                    readOnly
                    className="block w-full px-3 py-3 border border-gray-300 dark:border-gray-600 rounded-lg shadow-sm bg-gray-50 dark:bg-gray-800 text-gray-600 dark:text-gray-400 cursor-not-allowed"
                  />
                </div>
                <p className="mt-1 text-xs text-gray-500 dark:text-gray-400">
                  Fixed processing fee: 2.5%
                </p>
              </div>

              {/* Calculate Button */}
              <button
                type="button"
                onClick={calculateLoan}
                disabled={calculating || !formData.currency_id || !formData.loan_amount}
                className="w-full flex items-center justify-center px-4 py-3 border border-transparent text-sm font-medium rounded-lg text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors duration-200"
              >
                {calculating ? (
                  <ArrowPathIcon className="h-4 w-4 mr-2 animate-spin" />
                ) : (
                  <CalculatorIcon className="h-4 w-4 mr-2" />
                )}
                Calculate Loan Terms
              </button>
            </div>
          </div>

          {/* Calculation Results */}
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700 p-8">
            <h2 className="text-xl font-semibold text-gray-900 dark:text-white mb-6">
              Loan Summary
            </h2>

            {calculation ? (
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg">
                    <div className="text-sm text-blue-600 dark:text-blue-400">Loan Amount</div>
                    <div className="text-lg font-semibold text-gray-900 dark:text-white">
                      ${parseFloat(calculation.loan_amount_usd).toLocaleString()}
                    </div>
                    <div className="text-xs text-gray-500 dark:text-gray-400">
                      {parseFloat(calculation.loan_amount_currency).toLocaleString()} {calculation.currency.symbol}
                    </div>
                  </div>

                  <div className="p-4 bg-green-50 dark:bg-green-900/20 rounded-lg">
                    <div className="text-sm text-green-600 dark:text-green-400">Monthly Payment</div>
                    <div className="text-lg font-semibold text-gray-900 dark:text-white">
                      ${parseFloat(calculation.monthly_payment_usd).toLocaleString()}
                    </div>
                    <div className="text-xs text-gray-500 dark:text-gray-400">
                      Interest-free
                    </div>
                  </div>

                  <div className="p-4 bg-yellow-50 dark:bg-yellow-900/20 rounded-lg">
                    <div className="text-sm text-yellow-600 dark:text-yellow-400">Processing Fee</div>
                    <div className="text-lg font-semibold text-gray-900 dark:text-white">
                      ${parseFloat(calculation.fee_amount_usd).toLocaleString()}
                    </div>
                    <div className="text-xs text-gray-500 dark:text-gray-400">
                      {calculation.fee_percentage}% one-time
                    </div>
                  </div>

                  <div className="p-4 bg-purple-50 dark:bg-purple-900/20 rounded-lg">
                    <div className="text-sm text-purple-600 dark:text-purple-400">Total Cost</div>
                    <div className="text-lg font-semibold text-gray-900 dark:text-white">
                      ${parseFloat(calculation.total_amount_usd).toLocaleString()}
                    </div>
                    <div className="text-xs text-gray-500 dark:text-gray-400">
                      Over {formData.duration_months} months
                    </div>
                  </div>
                </div>

                {/* Exchange Rate Info */}
                <div className="p-4 bg-gray-50 dark:bg-gray-700 rounded-lg">
                  <div className="flex justify-between items-center">
                    <span className="text-sm text-gray-600 dark:text-gray-400">Exchange Rate</span>
                    <span className="font-medium text-gray-900 dark:text-white">
                      1 {calculation.currency.symbol} = ${parseFloat(calculation.exchange_rate).toFixed(8)}
                    </span>
                  </div>
                </div>

                {/* Apply Button */}
                <button
                  type="button"
                  onClick={submitApplication}
                  disabled={submitting}
                  className="w-full flex items-center justify-center px-4 py-3 border border-transparent text-sm font-medium rounded-lg text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 disabled:opacity-50 disabled:cursor-not-allowed transition-colors duration-200"
                >
                  {submitting ? (
                    <ArrowPathIcon className="h-4 w-4 mr-2 animate-spin" />
                  ) : (
                    <CheckCircleIcon className="h-4 w-4 mr-2" />
                  )}
                  Submit Application
                </button>

                {/* Terms Notice */}
                <div className="text-xs text-gray-500 dark:text-gray-400 text-center">
                  By submitting, you agree to our terms and conditions. 
                  Your application will be processed automatically.
                </div>
              </div>
            ) : (
              <div className="text-center py-12">
                <CalculatorIcon className="mx-auto h-12 w-12 text-gray-400" />
                <h3 className="mt-4 text-lg font-medium text-gray-900 dark:text-white">
                  Calculate Your Loan
                </h3>
                <p className="mt-2 text-sm text-gray-500 dark:text-gray-400">
                  Enter your loan details and click calculate to see the terms
                </p>
              </div>
            )}
          </div>
        </div>

        {/* Important Information */}
        <div className="mt-8 bg-blue-50 dark:bg-blue-900/20 rounded-xl p-6 border border-blue-200 dark:border-blue-700">
          <h3 className="text-lg font-medium text-blue-900 dark:text-blue-100 mb-4">
            Important Information
          </h3>
          <ul className="space-y-2 text-sm text-blue-800 dark:text-blue-200">
            <li>• <strong>Interest-Free:</strong> All loans are 0% interest with only processing fees</li>
            <li>• <strong>USD Denominated:</strong> Loan amount is fixed in USD to protect against volatility</li>
            <li>• <strong>Certificate Issued:</strong> You'll receive an ownership certificate for investment</li>
            <li>• <strong>Capimax Integration:</strong> Use your certificate on our partner investment platform</li>
            <li>• <strong>Automatic Processing:</strong> Most applications are approved instantly</li>
            <li>• <strong>Flexible Terms:</strong> Choose from 6 to 60-month repayment periods</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

export default LoanApplication;
